import React from 'react';
import { useFormik } from 'formik';
import * as Yup from 'yup';
import emailjs from 'emailjs-com';
import confetti from 'canvas-confetti';
import './FourthSection.css';

const FourthSection = () => {
  const initialValues = {
    name: '',
    email: '',
    subject: '',
    message: '',
  };

  const validationSchema = Yup.object({
    name: Yup.string().required('Required'),
    email: Yup.string().email('Invalid email address').required('Required'),
    subject: Yup.string().required('Required'),
    message: Yup.string().required('Required'),
  });

  const onSubmit = (values, { setSubmitting, resetForm }) => {
    emailjs
      .sendForm('service_hpeadoj', 'template_doikkmo', formRef.current, 'mxhVfavVsSqczEg8r')
      .then((result) => {
        console.log(result.text);
        const element = document.querySelector('#submitbutton');
        const { top, bottom, left, right } = element.getBoundingClientRect();
        confetti({
          origin: {
            x: ((left + right) / 2) / window.innerWidth,
            y: ((top + bottom) / 2) / window.innerHeight
          },
          spread: 90
        });
        element.value = '✅ Sent!';
        element.style.backgroundColor = '#00743b';
        setTimeout(() => {
          element.style.transition = 'background-color 0.5s, color 0.5s';
          element.style.backgroundColor = '';
          element.value = 'Submit';
        }, 3000);
      })
      .catch((error) => {
        console.log(error.text);
      })
      .finally(() => {
        setSubmitting(false);
        resetForm();
      });
  };

  const formik = useFormik({
    initialValues,
    validationSchema,
    onSubmit,
  });

  const formRef = React.useRef();

  return (
    <div className='fourthsection' data-aos="zoom-out-up" style={{ display: 'flex', alignItems: 'center', flexDirection: 'column' }}>
      <div className='desctypewriter' style={{ display: 'flex', flexDirection: 'row', gap: '4vw', position: 'relative' }}>
        {/* ... (rest of the code) */}
        <div className='contactmebox'>
          <form onSubmit={formik.handleSubmit} ref={formRef}>
            <h3>Get in touch.</h3>
            <div style={{ display: 'flex', flexDirection: 'row', gap: '2vw' }}>
              <input
                type="text"
                name='name'
                className='textBox'
                placeholder="name"
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.name}
              />
              <br />
              <input
                type="text"
                name='email'
                className='textBox'
                placeholder="email"
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.email}
              />
            </div>
            <div style={{ display: 'flex', flexDirection: 'column' }}>
              <input
                type="text"
                name='subject'
                className='textBox'
                placeholder="subject"
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.subject}
              />
              <textarea
                name='message'
                className='textBox'
                placeholder="message"
                style={{ height: '6vh', width: '95%' }}
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                value={formik.values.message}
              ></textarea>
              <input
                type="submit"
                className='submitbutton'
                value={formik.isSubmitting ? 'Sending...' : 'Submit'}
                id="submitbutton"
                disabled={formik.isSubmitting}
              />
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default FourthSection;
